using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create a sub component under root component
    Ptr occs = rootComp->occurrences();
    if (!occs)
        return false;

    Ptr transform = adsk::core::Matrix3D::create();
    if (!transform)
        return false;

    Ptr subOcc1 = occs->addNewComponent(transform);
    if (!subOcc1)
        return false;

    Ptr subComp1 = subOcc1->component();
    if (!subComp1)
        return false;

    std::string revisionId1 = subComp1->revisionId();

    // Create sketch 1 in sub component 1
    Ptr sketches1 = subComp1->sketches();
    if (!sketches1)
        return false;

    Ptr yzPlane = rootComp->yZConstructionPlane();
    if (!yzPlane)
        return false;

    Ptr sketch1 = sketches1->add(yzPlane);
    if (!sketch1)
        return false;

    // Get sketch curves
    Ptr sketchCurves = sketch1->sketchCurves();
    if (!sketchCurves)
        return false;

    // Get sketch lines
    Ptr sketchLines = sketchCurves->sketchLines();
    if (!sketchLines)
        return false;

    // Create sketch rectangle
    Ptr startPoint = Point3D::create(-8.0, 0, 0);

    Ptr endPoint = Point3D::create(8.0, 8.0, 0);
    sketchLines->addTwoPointRectangle(startPoint, endPoint);

    // Get the profile
    Ptr profs1 = sketch1->profiles();
    if (!profs1)
        return false;

    Ptr prof1 = profs1->item(0);

    // Create an extrusion input
    Ptr feats1 = subComp1->features();
    if (!feats1)
        return false;

    Ptr extrudes1 = feats1->extrudeFeatures();
    if (!extrudes1)
        return false;

    Ptr extInput1 = extrudes1->createInput(prof1, FeatureOperations::NewBodyFeatureOperation);

    // Define that the extent is a distance extent of 2 cm
    Ptr distance1 = ValueInput::createByReal(2.0);
    // Set the distance extent
    extInput1->setDistanceExtent(false, distance1);
    // Set the extrude type to be solid
    extInput1->isSolid(true);

    // Create the extrusion
    Ptr ext1 = extrudes1->add(extInput1);
    if (!ext1)
        return false;

    std::string revisionId2 = subComp1->revisionId();


    // Create a transform for second sub component
    Ptr translation = adsk::core::Vector3D::create(10, 0, 0);
    if (!translation)
        return false;

    Ptr transform2 = adsk::core::Matrix3D::create();
    if (!transform2)
        return false;

    transform2->translation(translation);

    // Create the second sub component
    Ptr subOcc2 = occs->addExistingComponent(subComp1, transform2);
    if (!subOcc2)
        return false;

    // Ground to parent
    subOcc1->isGroundToParent(false);
    subOcc2->isGroundToParent(true);


    return true;
}
